import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';

export default function Login() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [showPass, setShowPass] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(''); setLoading(true);
    try {
      await login(email, password);
      navigate('/dashboard');
    } catch (e: any) {
      setError(e.response?.data?.message || 'Invalid email or password');
    } finally { setLoading(false); }
  };

  return (
    <div style={{
      minHeight: '100vh',
      width: '100%',
      position: 'relative',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      fontFamily: "'DM Sans', sans-serif",
      overflow: 'hidden',
    }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,700;1,400&family=DM+Sans:wght@300;400;500;600&display=swap');
        @keyframes fadeIn { from { opacity:0; transform:translateY(20px); } to { opacity:1; transform:translateY(0); } }
        @keyframes shimmer { 0%,100% { opacity:.6; } 50% { opacity:1; } }
        .login-input:focus { border-color: #c9a84c !important; box-shadow: 0 0 0 3px rgba(201,168,76,0.15) !important; }
        .login-btn:hover { background: #c9a84c !important; transform: translateY(-1px); box-shadow: 0 8px 24px rgba(201,168,76,0.4) !important; }
        .login-btn:active { transform: translateY(0); }
      `}</style>

      {/* Background Image */}
      <div style={{
        position: 'absolute', inset: 0,
        backgroundImage: 'url(/library-bg.jpg)',
        backgroundSize: 'cover',
        backgroundPosition: 'center',
        filter: 'blur(3px) brightness(0.45)',
        transform: 'scale(1.05)',
      }} />

      {/* Gradient overlay */}


      {/* Decorative elements */}
      <div style={{ position:'absolute', top:60, left:60, width:200, height:200, borderRadius:'50%', background:'rgba(201,168,76,0.06)', filter:'blur(40px)' }} />
      <div style={{ position:'absolute', bottom:80, right:80, width:300, height:300, borderRadius:'50%', background:'rgba(99,102,241,0.08)', filter:'blur(60px)' }} />

      {/* Main Card */}
      <div style={{
        position: 'relative', zIndex: 10,
        width: '100%', maxWidth: 440,
        margin: '0 20px',
        animation: 'fadeIn .6s ease',
      }}>
        {/* Logo */}
        <div style={{ textAlign:'center', marginBottom:36 }}>
          <div style={{
            width:64, height:64, background:'linear-gradient(135deg,#c9a84c,#e8c96a)',
            borderRadius:18, display:'inline-flex', alignItems:'center', justifyContent:'center',
            fontSize:28, marginBottom:16,
            boxShadow:'0 8px 32px rgba(201,168,76,0.4)',
          }}>📖</div>
          <div style={{ fontFamily:"'Playfair Display',serif", fontSize:32, fontWeight:700, color:'#fff', letterSpacing:'-0.5px', lineHeight:1 }}>
            LibraryMS
          </div>
          <div style={{ fontSize:13, color:'rgba(255,255,255,0.45)', marginTop:8, letterSpacing:'0.1em', textTransform:'uppercase' }}>
            University Library System
          </div>
        </div>

        {/* Card */}
        <div style={{
          background:'rgba(255,255,255,0.07)',
          backdropFilter:'blur(24px)',
          WebkitBackdropFilter:'blur(24px)',
          border:'1px solid rgba(255,255,255,0.12)',
          borderRadius:24,
          padding:'36px 40px',
          boxShadow:'0 24px 64px rgba(0,0,0,0.4)',
        }}>
          <h2 style={{ fontFamily:"'Playfair Display',serif", fontSize:26, fontWeight:700, color:'#fff', marginBottom:6 }}>
            Welcome back
          </h2>
          <p style={{ fontSize:13, color:'rgba(255,255,255,0.45)', marginBottom:28 }}>
            Sign in to access your library account
          </p>

          {error && (
            <div style={{
              background:'rgba(220,38,38,0.15)', border:'1px solid rgba(220,38,38,0.3)',
              color:'#fca5a5', padding:'12px 16px', borderRadius:12, fontSize:13, marginBottom:20,
              display:'flex', alignItems:'center', gap:8,
            }}>
              <span>⚠</span> {error}
            </div>
          )}

          <form onSubmit={handleSubmit}>
            {/* Email */}
            <div style={{ marginBottom:18 }}>
              <label style={{ display:'block', fontSize:12, fontWeight:600, color:'rgba(255,255,255,0.6)', marginBottom:8, letterSpacing:'0.05em', textTransform:'uppercase' }}>
                Email Address
              </label>
              <input
                className="login-input"
                type="email"
                value={email}
                onChange={e => setEmail(e.target.value.toLowerCase())}
                placeholder="your@email.com"
                required
                style={{
                  width:'100%', padding:'13px 16px',
                  background:'rgba(255,255,255,0.08)',
                  border:'1.5px solid rgba(255,255,255,0.12)',
                  borderRadius:12, fontSize:14,
                  color:'#fff', fontFamily:'inherit',
                  outline:'none', transition:'all .2s',
                  boxSizing:'border-box',
                }}
              />
            </div>

            {/* Password */}
            <div style={{ marginBottom:28 }}>
              <label style={{ display:'block', fontSize:12, fontWeight:600, color:'rgba(255,255,255,0.6)', marginBottom:8, letterSpacing:'0.05em', textTransform:'uppercase' }}>
                Password
              </label>
              <div style={{ position:'relative' }}>
                <input
                  className="login-input"
                  type={showPass ? 'text' : 'password'}
                  value={password}
                  onChange={e => setPassword(e.target.value)}
                  placeholder="••••••••"
                  required
                  style={{
                    width:'100%', padding:'13px 48px 13px 16px',
                    background:'rgba(255,255,255,0.08)',
                    border:'1.5px solid rgba(255,255,255,0.12)',
                    borderRadius:12, fontSize:14,
                    color:'#fff', fontFamily:'inherit',
                    outline:'none', transition:'all .2s',
                    boxSizing:'border-box',
                  }}
                />
                <button type="button" onClick={() => setShowPass(!showPass)}
                  style={{ position:'absolute', right:14, top:'50%', transform:'translateY(-50%)', background:'none', border:'none', color:'rgba(255,255,255,0.4)', cursor:'pointer', fontSize:16, padding:0 }}>
                  {showPass ? '🙈' : '👁'}
                </button>
              </div>
            </div>

            {/* Submit */}
            <button
              type="submit"
              className="login-btn"
              disabled={loading}
              style={{
                width:'100%', padding:'14px',
                background:'#1a1a2e',
                border:'1.5px solid rgba(201,168,76,0.4)',
                borderRadius:12, fontSize:15, fontWeight:600,
                color:'#fff', cursor:'pointer',
                fontFamily:'inherit', transition:'all .25s',
                letterSpacing:'0.02em',
                opacity: loading ? 0.7 : 1,
              }}>
              {loading ? (
                <span style={{ display:'flex', alignItems:'center', justifyContent:'center', gap:8 }}>
                  <span style={{ width:16, height:16, border:'2px solid rgba(255,255,255,0.3)', borderTopColor:'#fff', borderRadius:'50%', display:'inline-block', animation:'spin 1s linear infinite' }} />
                  Signing in...
                </span>
              ) : 'Sign In →'}
            </button>
          </form>

          {/* Register link */}
          <div style={{ textAlign:'center', marginTop:22, paddingTop:22, borderTop:'1px solid rgba(255,255,255,0.08)' }}>
            <p style={{ fontSize:13, color:'rgba(255,255,255,0.4)' }}>
              New student or staff?{' '}
              <Link to="/register" style={{ color:'#c9a84c', fontWeight:600, textDecoration:'none' }}>
                Create Account
              </Link>
            </p>
          </div>
        </div>

        {/* Bottom note */}
        <div style={{ textAlign:'center', marginTop:20 }}>
          <p style={{ fontSize:11, color:'rgba(255,255,255,0.25)', letterSpacing:'0.05em' }}>
            PROTECTED BY LIBRARY MANAGEMENT SYSTEM
          </p>
        </div>
      </div>

      <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
    </div>
  );
}
